module RefModule (
    input clk,
    input sreset,
    output [2:0] q );reg [2:0] unused_q_reg;

    always @(posedge clk) begin
        if (sreset)
            unused_q_reg <= 3'b000;
        else
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
